:root{--bg:#f6f6f6;
    --card:#fff;
    --text:#141414;
    --muted:#7a7a7a;
    --line:#e8e8e8;
    --blue:#2563eb;
    --green:#12a150}
    *{box-sizing:border-box}
body{margin:0;
    background:var(--bg);
    color:var(--text);
    font-family:"DM Sans",sans-serif}

a{text-decoration:none;
    color:inherit}
button,input{font:inherit}
.top-nav{max-width:1240px;
    margin:0 auto;
    padding:26px 32px 18px;
    display:flex;
    align-items:center;
    justify-content:space-between;
    gap:20px}

.logo{display:inline-flex;
    align-items:center;
    gap:10px;
    font-weight:800;
    font-size:28px}
.logo svg{width:32px;height:32px}
.nav-links{
    list-style:none;
    display:flex;
    gap:34px;
    padding:0;
    margin:0;font-size:12px;
    letter-spacing:.08em}

.nav-links a.active{color:var(--blue)}
.nav-actions{
    display:flex;
    align-items:center;
    gap:14px}
.page-shell{
    max-width:1240px;
    margin:0 auto;
    padding:12px 32px 70px
 }
.search-card{
    background:var(--card);
    border:1px solid var(--line);
    border-radius:14px;
    padding:28px;
    display:flex;
    justify-content:space-between;
    gap:24px;
    align-items:center;
    box-shadow:0 10px 22px rgba(0,0,0,.03)}
.search-copy h1{margin:0 0 8px;font-size:36px;color:var(--blue)}
.search-copy p{margin:0 0 14px;color:var(--muted)}
.region-chip{
    display:inline-block;
    background:#e8f7ee;
    color:var(--green);
    border-radius:999px;
    padding:6px 12px;
    font-size:12px}
.search-actions{
    display:flex;align-items:center;gap:10px}
.search-input{
    display:flex;align-items:center;gap:10px;min-width:320px;background:#fafafa;border:1px solid var(--line);border-radius:10px;padding:12px 14px;color:#999}
.search-input input{
    border:0;outline:0;width:100%;background:transparent}
.quick-book,.apply-btn,.load-more{
    border:0;background:var(--green);color:#fff;border-radius:8px;padding:6px 14px;font-weight:600}
.content-grid{
    margin-top:24px;display:grid;grid-template-columns:270px 1fr;gap:24px}
.filters-card,.tour-card{
    background:var(--card);
    border:1px solid var(--line);
    border-radius:16px;
    box-shadow:0 8px 18px rgba(0,0,0,.03)}
.filters-card{
    padding:22px;
    align-self:start}
.filters-card h3{
    margin:0 0 18px;
    font-size:16px}
.filter-group{margin-bottom:22px}
.filter-title{font-weight:700;margin-bottom:10px;font-size:14px}
.range-row{display:flex;justify-content:space-between;color:var(--muted);font-size:12px;margin-bottom:10px}
.filters-card label{display:block;margin:8px 0;color:var(--muted);font-size:14px}
.stars{color:#111;font-size:14px}
.stars span{color:var(--muted)}
.filter-actions{display:flex;gap:10px;align-items:center}
.reset-btn{background:transparent;border:0;color:var(--muted)}
.tour-grid{display:grid;grid-template-columns:repeat(3,minmax(0,1fr));gap:20px}
.tour-card{overflow:hidden}
.tour-card img{width:100%;height:180px;object-fit:cover;display:block}
.tour-content{padding:16px}
.tour-meta-top{display:flex;align-items:center;justify-content:space-between;gap:10px;color:var(--muted);font-size:12px}
.badge{background:#dff6e8;color:var(--green);padding:4px 10px;border-radius:999px}
.tour-content h3{margin:12px 0 4px;font-size:20px}
.tour-content p{margin:0 0 14px;color:var(--muted);font-size:14px}
.tour-bottom{display:flex;justify-content:space-between;gap:10px;align-items:end;margin-bottom:14px}
.tour-rating{font-size:13px}
.tour-rating span,.tour-bottom small{color:var(--muted)}
.tour-price{color:var(--muted);font-size:13px;text-align:right}
.tour-price strong{display:block;color:var(--green);font-size:22px}
.details-btn{display:inline-flex;background:var(--blue);color:#fff;padding:10px 16px;border-radius:10px;font-size:13px;font-weight:600}
.pagination-row{display:flex;justify-content:end;align-items:center;gap:12px;margin-top:20px}
.pages{display:flex;gap:8px}
.pages button{width:32px;height:32px;border-radius:50%;border:1px solid var(--line);background:#fff}
.footer{border-top:1px solid #d7d7d7;padding:52px 32px 28px;background:var(--bg)}
.footer-top{max-width:1240px;margin:0 auto;display:flex;justify-content:space-between;gap:30px}
.footer-brand{max-width:260px}
.footer-logo{margin-bottom:12px}
.footer-brand p{color:var(--muted);line-height:1.5}
.social-row{display:flex;gap:12px;align-items:center;margin-top:18px}
.social-icons{display:flex;gap:8px}
.social-icons a{width:28px;height:28px;border-radius:50%;border:1px solid var(--line);display:inline-flex;align-items:center;justify-content:center;font-size:12px}
.footer-links{display:grid;grid-template-columns:repeat(3,minmax(140px,1fr));gap:40px}
.footer-links h4{margin-top:0;margin-bottom:14px}
.footer-links a{display:block;color:var(--muted);margin-bottom:10px;font-size:14px}
.footer-bottom{max-width:1240px;margin:30px auto 0;padding-top:20px;border-top:1px solid #d7d7d7;text-align:center;color:var(--muted);font-size:13px}

.pages button.active{background:var(--text);color:#fff;border-color:var(--text);font-weight:700}
.pages button:hover:not(.active){background:#f0f0f0}
.pg-arrow{width:32px;height:32px;border-radius:50%;border:1px solid var(--line);background:#fff;font-size:18px;cursor:pointer;display:flex;align-items:center;justify-content:center;transition:background .15s}
.pg-arrow:hover{background:#f0f0f0}
.pg-arrow:disabled{opacity:.35;cursor:default}





    @media (max-width:1050px){
        .content-grid{grid-template-columns:1fr}
        .tour-grid{grid-template-columns:repeat(2,minmax(0,1fr))}
        .search-card,.top-nav,.footer-top{flex-direction:column;align-items:flex-start}
        .footer-links{grid-template-columns:repeat(2,minmax(140px,1fr))}
    }
    @media (max-width:720px){
        .top-nav,.page-shell,.footer{padding-left:18px;padding-right:18px}
        .nav-links{gap:16px;flex-wrap:wrap}
        .search-actions{width:100%;flex-direction:column;align-items:stretch}
        .search-input{min-width:0;width:100%}
        .tour-grid,.footer-links{grid-template-columns:1fr}}

