    max-width:1240px;
    margin:0 auto;
    padding:12px 32px 70px
 }
.search-card{
    background:var(--card);
    border:1px solid var(--line);
    border-radius:14px;
    padding:28px;
    display:flex;
    justify-content:space-between;
    gap:24px;
    align-items:center;
    box-shadow:0 10px 22px rgba(0,0,0,.03)}
.search-copy h1{margin:0 0 8px;font-size:36px;color:var(--blue)}
.search-copy p{margin:0 0 14px;color:var(--muted)}
.region-chip{
    display:inline-block;
    background:#e8f7ee;
    color:var(--green);
    border-radius:999px;
    padding:6px 12px;
    font-size:12px}
.search-actions{
    display:flex;align-items:center;gap:10px}
.search-input{
    display:flex;align-items:center;gap:10px;min-width:320px;background:#fafafa;border:1px solid var(--line);border-radius:10px;padding:12px 14px;color:#999}
.search-input input{
    border:0;outline:0;width:100%;background:transparent}
.quick-book,.apply-btn,.load-more{
    border:0;background:var(--green);color:#fff;border-radius:8px;padding:6px 14px;font-weight:600}
.content-grid{
    margin-top:24px;display:grid;grid-template-columns:270px 1fr;gap:24px}
.filters-card,.tour-card{
    background:var(--card);
    border:1px solid var(--line);
    border-radius:16px;
    box-shadow:0 8px 18px rgba(0,0,0,.03)}
.filters-card{
    padding:22px;
    align-self:start}
.filters-card h3{
    margin:0 0 18px;
    font-size:16px}
.filter-group{margin-bottom:22px}
.filter-title{font-weight:700;margin-bottom:10px;font-size:14px}
.range-row{display:flex;justify-content:space-between;color:var(--muted);font-size:12px;margin-bottom:10px}
.filters-card label{display:block;margin:8px 0;color:var(--muted);font-size:14px}
.stars{color:#111;font-size:14px}
.stars span{color:var(--muted)}
.filter-actions{display:flex;gap:10px;align-items:center}
.reset-btn{background:transparent;border:0;color:var(--muted)}
.tour-grid{display:grid;grid-template-columns:repeat(3,minmax(0,1fr));gap:20px}
.tour-card{overflow:hidden}
.tour-card img{width:100%;height:180px;object-fit:cover;display:block}
.tour-content{padding:16px}
.tour-meta-top{display:flex;align-items:center;justify-content:space-between;gap:10px;color:var(--muted);font-size:12px}
.badge{background:#dff6e8;color:var(--green);padding:4px 10px;border-radius:999px}
.tour-content h3{margin:12px 0 4px;font-size:20px}
.tour-content p{margin:0 0 14px;color:var(--muted);font-size:14px}
.tour-bottom{display:flex;justify-content:space-between;gap:10px;align-items:end;margin-bottom:14px}
.tour-rating{font-size:13px}
.tour-rating span,.tour-bottom small{color:var(--muted)}
.tour-price{color:var(--muted);font-size:13px;text-align:right}
.tour-price strong{display:block;color:var(--green);font-size:22px}
.details-btn{display:inline-flex;background:var(--blue);color:#fff;padding:10px 16px;border-radius:10px;font-size:13px;font-weight:600}
.pagination-row{display:flex;justify-content:end;align-items:center;gap:12px;margin-top:20px}
.pagination-row--hidden{display:none}
.pages{display:flex;gap:8px}
.pages button{width:32px;height:32px;border-radius:50%;border:1px solid var(--line);background:#fff}
.footer{border-top:1px solid #d7d7d7;padding:52px 32px 28px;background:var(--bg)}
.footer-top{max-width:1240px;margin:0 auto;display:flex;justify-content:space-between;gap:30px}
.footer-brand{max-width:260px}
.footer-logo{margin-bottom:12px}
.footer-brand p{color:var(--muted);line-height:1.5}
.social-row{display:flex;gap:12px;align-items:center;margin-top:18px}
.social-icons{display:flex;gap:8px}
.social-icons a{width:28px;height:28px;border-radius:50%;border:1px solid var(--line);display:inline-flex;align-items:center;justify-content:center;font-size:12px}
.footer-links{display:grid;grid-template-columns:repeat(3,minmax(140px,1fr));gap:40px}
.footer-links h4{margin-top:0;margin-bottom:14px}
.footer-links a{display:block;color:var(--muted);margin-bottom:10px;font-size:14px}
.footer-bottom{max-width:1240px;margin:30px auto 0;padding-top:20px;border-top:1px solid #d7d7d7;text-align:center;color:var(--muted);font-size:13px}

.pages button.active{background:var(--text);color:#fff;border-color:var(--text);font-weight:700}
.pages button:hover:not(.active){background:#f0f0f0}
.pg-arrow{width:32px;height:32px;border-radius:50%;border:1px solid var(--line);background:#fff;font-size:18px;cursor:pointer;display:flex;align-items:center;justify-content:center;transition:background .15s}
.pg-arrow:hover{background:#f0f0f0}
.pg-arrow:disabled{opacity:.35;cursor:default}

.tour-grid--loading{display:flex;align-items:center;justify-content:center;min-height:320px}
.tour-loader{
    grid-column:1/-1;
    display:flex;
    flex-direction:column;
    align-items:center;
    justify-content:center;
    gap:14px;
    min-height:280px;
    color:var(--muted);
    text-align:center;
}
.tour-loader p{margin:0;font-weight:600}
.tour-spinner{
    width:52px;
    height:52px;
    border-radius:50%;
    border:4px solid rgba(37, 99, 235, .12);
    border-top-color:var(--blue);
    animation:tourSpin 1s linear infinite;
}
.tour-empty-state,
.tour-error-state{
    background:#fff;
    border:1px solid var(--line);
    border-radius:16px;
    box-shadow:0 8px 18px rgba(0,0,0,.03);
    padding:28px;
}

@keyframes tourSpin{
    from{transform:rotate(0deg)}
    to{transform:rotate(360deg)}
}





    @media (max-width:1050px){
        .content-grid{grid-template-columns:1fr}
        .tour-grid{grid-template-columns:repeat(2,minmax(0,1fr))}
        .search-card,.top-nav,.footer-top{flex-direction:column;align-items:flex-start}
        .footer-links{grid-template-columns:repeat(2,minmax(140px,1fr))}
    }
    @media (max-width:720px){
        .top-nav,.page-shell,.footer{padding-left:18px;padding-right:18px}
        .nav-links{gap:16px;flex-wrap:wrap}
        .search-actions{width:100%;flex-direction:column;align-items:stretch}
        .search-input{min-width:0;width:100%}
        .tour-grid,.footer-links{grid-template-columns:1fr}
        .tour-grid--loading{min-height:240px}
    }

/**
 * Tours Page - API Integration
 * Loads tours from backend and manages filtering & pagination
 */

(async function () {


  const PER_PAGE = 6;

  let allTours = [];
  let filteredTours = [];
  let totalPages = 0;
  let currentPage = 0;

  const pgButtonsEl = document.getElementById('pgButtons');
  const pgPrev       = document.getElementById('pgPrev');
  const pgNext       = document.getElementById('pgNext');
  const tourGrid     = document.querySelector('.tour-grid');

  // ──────────────────────────────────────────────────────────────────
  // Load tours from API
  // ──────────────────────────────────────────────────────────────────
  async function loadTours() {
    try {
      const response = await api.listTours();
      allTours = response.tours || [];
      filteredTours = [...allTours];
      buildButtons();
      showPage(0);
    } catch (error) {
      console.error('Failed to load tours:', error);
      tourGrid.innerHTML = '<div style="grid-column: 1/-1; text-align: center; padding: 2em;">Failed to load tours. Please try again.</div>';
    }
  }

  // ──────────────────────────────────────────────────────────────────
  // Render tour card HTML
  // ──────────────────────────────────────────────────────────────────
  function createTourCard(tour) {
    const card = document.createElement('article');
    card.className = 'tour-card';

    const imageUrl = `/images/${tour.id}.jpg`; // Change when you have backend image storage
    const rating = '★★★★☆';
    const ratingCount = '4.8 (3,624)';
    const spot = tour.seats_available > 0 ? tour.seats_available : 'Full';

    card.innerHTML = `
      <img src="${imageUrl}" alt="${tour.title}" onerror="this.src='https://via.placeholder.com/300x200?text=${encodeURIComponent(tour.title)}'">
      <div class="tour-content">
        <div class="tour-meta-top">
          <span>${tour.duration_hours || 2} hours · Day trip</span>
          <span class="badge">Nature</span>
        </div>
        <h3>${tour.title}</h3>
        <p>${tour.location_name}</p>
        <div class="tour-bottom">
          <div>
            <div class="tour-rating">${rating} <span>${ratingCount}</span></div>
            <small>Spots left: ${spot}</small>
          </div>
          <div class="tour-price">From <strong>${Math.round(tour.price).toLocaleString()} ₸</strong></div>
        </div>
        <a href="tour_detail.html?tour=${tour.id}&from=api" class="details-btn">View Details</a>
      </div>
    `;
    return card;
  }

  // ──────────────────────────────────────────────────────────────────
  // Build (render) page buttons
  // ──────────────────────────────────────────────────────────────────
  function buildButtons() {
    pgButtonsEl.innerHTML = '';
    totalPages = Math.ceil(filteredTours.length / PER_PAGE);
    for (let i = 0; i < totalPages; i++) {
      const btn = document.createElement('button');
      btn.textContent = i + 1;
      btn.addEventListener('click', () => goTo(i));
      pgButtonsEl.appendChild(btn);
    }
  }

  // ──────────────────────────────────────────────────────────────────
  // Show page
  // ──────────────────────────────────────────────────────────────────
  function showPage(p) {
    currentPage = p;

    // Clear grid
    tourGrid.innerHTML = '';

    // Get tours for this page
    const start = p * PER_PAGE;
    const end = start + PER_PAGE;
    const pageToTours = filteredTours.slice(start, end);

    // Render cards
    pageToTours.forEach(tour => {
      tourGrid.appendChild(createTourCard(tour));
    });

    // Update button states
    [...pgButtonsEl.children].forEach((btn, i) => {
      btn.classList.toggle('active', i === p);
    });

    pgPrev.disabled = p === 0 || totalPages === 0;
    pgNext.disabled = p >= totalPages - 1;

    // Scroll to top
    tourGrid.scrollIntoView({ behavior: 'smooth', block: 'start' });
  }

  function goTo(p) {
    if (p < 0 || p >= totalPages) return;
    showPage(p);
  }

  function changePage(delta) {
    const next = currentPage + delta;
    if (next >= 0 && next < totalPages) goTo(next);
  }

  window.changePage = changePage;

  // ──────────────────────────────────────────────────────────────────
  // Filtering
  // ──────────────────────────────────────────────────────────────────
  const applyBtn = document.querySelector('.apply-btn');
  const resetBtn = document.querySelector('.reset-btn');
  const searchInput = document.querySelector('.search-input input');
  const priceRange = document.querySelector('input[type="range"]');
  const typeCheckboxes = document.querySelectorAll('.filter-group:nth-of-type(4) input[type="checkbox"]');

  function applyFilters() {
    const searchTerm = searchInput.value.toLowerCase().trim();
    const maxPrice = parseInt(priceRange.value, 10);

    const checkedTypes = Array.from(typeCheckboxes)
      .filter(cb => cb.checked)
      .map(cb => cb.parentElement.textContent.trim());

    filteredTours = allTours.filter(tour => {
      // 1. Price filter
      if (Math.round(tour.price) > maxPrice) return false;

      // 2. Type filter (placeholder - adjust based on your tour types)
      if (checkedTypes.length > 0) {
        // Add your logic here to match tour types
      }

      // 3. Text search
      if (searchTerm) {
        const title = tour.title.toLowerCase();
        const desc = (tour.description || '').toLowerCase();
        const location = (tour.location_name || '').toLowerCase();
        if (!title.includes(searchTerm) && !desc.includes(searchTerm) && !location.includes(searchTerm)) {
          return false;
        }
      }

      return true;
    });

    currentPage = 0;
    buildButtons();
    showPage(0);
  }

  if (applyBtn) applyBtn.addEventListener('click', applyFilters);
  if (resetBtn) {
    resetBtn.addEventListener('click', () => {
      priceRange.value = 35000;
      Array.from(typeCheckboxes).forEach(cb => cb.checked = false);
      searchInput.value = '';
      applyFilters();
    });
  }

  if (searchInput) {
    searchInput.addEventListener('keyup', (e) => {
      if (e.key === 'Enter') applyFilters();
    });
  }

  // ──────────────────────────────────────────────────────────────────
  // Initial load
  // ──────────────────────────────────────────────────────────────────
  await loadTours();
})();

/**
 * Tours Page - API Integration
 * Loads tours from backend and manages filtering & pagination
 */

(async function () {
  const PER_PAGE = 6;

  let allTours = [];
  let filteredTours = [];
  let totalPages = 0;
  let currentPage = 0;

  const pgButtonsEl = document.getElementById('pgButtons');
  const pgPrev = document.getElementById('pgPrev');
  const pgNext = document.getElementById('pgNext');
  const tourGrid = document.querySelector('.tour-grid');
  const paginationRow = document.querySelector('.pagination-row');
  const applyBtn = document.querySelector('.apply-btn');
  const resetBtn = document.querySelector('.reset-btn');
  const searchInput = document.querySelector('.search-input input');
  const priceRange = document.querySelector('input[type="range"]');
  const typeCheckboxes = document.querySelectorAll('.filter-group:nth-of-type(4) input[type="checkbox"]');

  function escapeHtml(value) {
    return String(value ?? '')
      .replace(/&/g, '&amp;')
      .replace(/</g, '&lt;')
      .replace(/>/g, '&gt;')
      .replace(/"/g, '&quot;')
      .replace(/'/g, '&#39;');
  }

  function getTourKey(tour) {
    return String(tour?.slug || tour?.id || '');
  }

  function formatDurationLabel(tour) {
    if (tour?.meta_text) return tour.meta_text;

    const hours = Number(tour?.duration_hours);
    if (!Number.isFinite(hours) || hours <= 0) return 'Day trip';

    const hoursText = Number.isInteger(hours) ? `${hours} hours` : `${hours.toFixed(1)} hours`;
    const tripKind = hours <= 5 ? 'Half day' : 'Day trip';
    return `${hoursText} · ${tripKind}`;
  }

  function renderStars(rating) {
    const safeRating = Number(rating);
    const filled = Number.isFinite(safeRating) ? Math.max(0, Math.min(5, Math.round(safeRating))) : 5;
    return '★'.repeat(filled) + '☆'.repeat(5 - filled);
  }

  function formatRatingText(tour) {
    const rating = Number(tour?.rating);
    const ratingValue = Number.isFinite(rating) ? rating.toFixed(1) : '4.8';
    const count = Number(tour?.rating_count);
    const ratingCount = Number.isFinite(count) ? count.toLocaleString() : '3,624';
    return `${ratingValue} (${ratingCount})`;
  }

  function formatPrice(price) {
    const value = Number(price) || 0;
    return `${Math.round(value).toLocaleString()} ₸`;
  }

  function resolveImageUrl(tour) {
    return tour?.image_url || `https://via.placeholder.com/800x600?text=${encodeURIComponent(tour?.title || 'AlmaTour')}`;
  }

  function setPaginationVisibility(visible) {
    if (!paginationRow) return;
    paginationRow.classList.toggle('pagination-row--hidden', !visible);
  }

  function renderLoadingState() {
    if (!tourGrid) return;
    tourGrid.classList.add('tour-grid--loading');
    tourGrid.setAttribute('aria-busy', 'true');
    tourGrid.innerHTML = `
      <div class="tour-loader" role="status" aria-live="polite" aria-label="Loading tours">
        <span class="tour-spinner" aria-hidden="true"></span>
        <p>Loading tours...</p>
      </div>
    `;
    setPaginationVisibility(false);
  }

  function renderEmptyState(message) {
    if (!tourGrid) return;
    tourGrid.classList.remove('tour-grid--loading');
    tourGrid.removeAttribute('aria-busy');
    tourGrid.innerHTML = `
      <div class="tour-loader tour-empty-state" role="status">
        <p>${escapeHtml(message)}</p>
      </div>
    `;
    setPaginationVisibility(false);
  }

  function renderErrorState(message) {
    if (!tourGrid) return;
    tourGrid.classList.remove('tour-grid--loading');
    tourGrid.removeAttribute('aria-busy');
    tourGrid.innerHTML = `
      <div class="tour-loader tour-error-state">
        <p>${escapeHtml(message)}</p>
        <button class="apply-btn" type="button" id="retryLoadTours">Retry</button>
      </div>
    `;
    setPaginationVisibility(false);

    const retryBtn = document.getElementById('retryLoadTours');
    if (retryBtn) retryBtn.addEventListener('click', loadTours);
  }

  function createTourCard(tour) {
    const card = document.createElement('article');
    card.className = 'tour-card';

    const tourKey = getTourKey(tour);
    const ratingValue = Number(tour?.rating);
    const badge = tour?.badge || 'Nature';
    const spotsLeft = tour?.spots_left ?? tour?.seats_available ?? '—';

    card.innerHTML = `
      <img src="${escapeHtml(resolveImageUrl(tour))}" alt="${escapeHtml(tour?.title || 'Tour')}" loading="lazy" onerror="this.src='https://via.placeholder.com/800x600?text=${encodeURIComponent(tour?.title || 'AlmaTour')}'">
      <div class="tour-content">
        <div class="tour-meta-top">
          <span>${escapeHtml(formatDurationLabel(tour))}</span>
          <span class="badge">${escapeHtml(badge)}</span>
        </div>
        <h3>${escapeHtml(tour?.title || 'Untitled tour')}</h3>
        <p>${escapeHtml(tour?.location_name || 'Almaty region')}</p>
        <div class="tour-bottom">
          <div>
            <div class="tour-rating">${renderStars(ratingValue)} <span>${escapeHtml(formatRatingText(tour))}</span></div>
            <small>Spots left: ${escapeHtml(spotsLeft)}</small>
          </div>
          <div class="tour-price">From <strong>${escapeHtml(formatPrice(tour?.price))}</strong></div>
        </div>
        <a href="tour_detail.html?tour=${encodeURIComponent(tourKey)}&from=api" class="details-btn">View Details</a>
      </div>
    `;
    return card;
  }

  function buildButtons() {
    if (!pgButtonsEl) return;
    pgButtonsEl.innerHTML = '';
    totalPages = Math.ceil(filteredTours.length / PER_PAGE);

    for (let i = 0; i < totalPages; i++) {
      const btn = document.createElement('button');
      btn.type = 'button';
      btn.textContent = i + 1;
      btn.addEventListener('click', () => goTo(i));
      pgButtonsEl.appendChild(btn);
    }
  }

  function updatePaginationState() {
    if (pgPrev) pgPrev.disabled = currentPage === 0 || totalPages === 0;
    if (pgNext) pgNext.disabled = currentPage >= totalPages - 1 || totalPages === 0;

    if (pgButtonsEl) {
      [...pgButtonsEl.children].forEach((btn, i) => {
        btn.classList.toggle('active', i === currentPage);
      });
    }
  }

  function showPage(pageIndex) {
    if (!tourGrid) return;

    currentPage = pageIndex;
    tourGrid.classList.remove('tour-grid--loading');
    tourGrid.removeAttribute('aria-busy');
    tourGrid.innerHTML = '';

    if (filteredTours.length === 0) {
      renderEmptyState('No tours match your filters yet.');
      return;
    }

    const start = pageIndex * PER_PAGE;
    const pageTours = filteredTours.slice(start, start + PER_PAGE);
    pageTours.forEach((tour) => tourGrid.appendChild(createTourCard(tour)));

    updatePaginationState();
    setPaginationVisibility(true);
    tourGrid.scrollIntoView({ behavior: 'smooth', block: 'start' });
  }

  function goTo(pageIndex) {
    if (pageIndex < 0 || pageIndex >= totalPages) return;
    showPage(pageIndex);
  }

  function changePage(delta) {
    const next = currentPage + delta;
    if (next >= 0 && next < totalPages) goTo(next);
  }

  window.changePage = changePage;

  function applyFilters() {
    const searchTerm = searchInput ? searchInput.value.toLowerCase().trim() : '';
    const maxPrice = priceRange ? parseInt(priceRange.value, 10) : Number.POSITIVE_INFINITY;

    const checkedTypes = Array.from(typeCheckboxes)
      .filter((cb) => cb.checked)
      .map((cb) => cb.parentElement.textContent.trim().toLowerCase());

    filteredTours = allTours.filter((tour) => {
      if (Number(tour.price) > maxPrice) return false;

      const tourType = String(tour.badge || '').trim().toLowerCase();
      if (checkedTypes.length > 0 && !checkedTypes.includes(tourType)) return false;

      if (searchTerm) {
        const title = String(tour.title || '').toLowerCase();
        const desc = String(tour.description || '').toLowerCase();
        const location = String(tour.location_name || '').toLowerCase();
        const meta = String(tour.meta_text || '').toLowerCase();
        if (!title.includes(searchTerm) && !desc.includes(searchTerm) && !location.includes(searchTerm) && !meta.includes(searchTerm)) {
          return false;
        }
      }

      return true;
    });

    currentPage = 0;
    buildButtons();
    showPage(0);
  }

  async function loadTours() {
    renderLoadingState();

    try {
      if (typeof api === 'undefined') {
        throw new Error('API client is not available');
      }

      const response = await api.listTours();
      allTours = response?.tours || [];
      filteredTours = [...allTours];
      currentPage = 0;
      buildButtons();

      if (filteredTours.length === 0) {
        renderEmptyState('No tours available yet.');
        return;
      }

      showPage(0);
    } catch (error) {
      console.error('Failed to load tours:', error);
      renderErrorState('Failed to load tours. Please try again.');
    }
  }

  if (applyBtn) applyBtn.addEventListener('click', applyFilters);
  if (resetBtn) {
    resetBtn.addEventListener('click', () => {
      if (priceRange) priceRange.value = priceRange.max || 35000;
      Array.from(typeCheckboxes).forEach((cb) => (cb.checked = false));
      if (searchInput) searchInput.value = '';
      applyFilters();
    });
  }

  if (searchInput) {
    searchInput.addEventListener('keyup', (e) => {
      if (e.key === 'Enter') applyFilters();
    });
  }

  await loadTours();
})();
